mapper.select:
SELECT br.*, u.real_name AS user_name, u.real_name AS user_real_name, b.title AS book_title, b.isbn AS book_isbn, b.cover_image AS book_cover_image, COALESCE(f.fine_amount, 0) AS fine_amount FROM borrow_record br LEFT JOIN sys_user u ON br.user_id = u.id LEFT JOIN book b ON br.book_id = b.id LEFT JOIN ( SELECT borrow_id, SUM(amount) AS fine_amount FROM fine_record WHERE deleted = 0 GROUP BY borrow_id ) f ON br.id = f.borrow_id WHERE br.deleted = 0
AND (u.real_name LIKE CONCAT('%', #{keyword}, '%') OR b.title LIKE CONCAT('%', #{keyword}, '%'))
AND br.status = #{status}
AND br.user_id = #{userId}
ORDER BY br.create_time DESC
